import org.apache.commons.text.StringEscapeUtils;

public class XSSFixedCode {

    public static void main(String[] args) {
        // Simulating user input from a form field
        String userInput = "<script>alert('XSS Vulnerability!')</script>";

        // Escaping special characters in user input
        String sanitizedInput = StringEscapeUtils.escapeHtml4(userInput);

        // Displaying the sanitized user input back to the user
        System.out.println("Sanitized User input: " + sanitizedInput);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
